import type { ReactNode } from "react";
import {
  IconInfoCircle,
  IconBulb,
  IconAlertTriangle,
} from "@tabler/icons-react";

/**
 * Local note/warning/tip callout.
 *
 * NOTE: @gunjo/ui ships <DocNote>, but it only exposes two variants
 * ("default" | "reference") with no note/warning/tip semantics, no icon,
 * and renders its heading as a plain <div>. For a real article we need
 * the three semantic callout types, so this is a page-local composition.
 * Tracked as a candidate for a `DocNote variant="note|warning|tip"` API
 * upstream rather than shipped as a one-off.
 */
type CalloutVariant = "note" | "warning" | "tip";

const variantConfig: Record<
  CalloutVariant,
  { icon: typeof IconInfoCircle; className: string; iconClass: string; label: string }
> = {
  note: {
    icon: IconInfoCircle,
    className: "border-primary/30 bg-primary/5",
    iconClass: "text-primary",
    label: "メモ",
  },
  tip: {
    icon: IconBulb,
    className: "border-success/30 bg-success/5",
    iconClass: "text-success",
    label: "ヒント",
  },
  warning: {
    icon: IconAlertTriangle,
    className: "border-warning/40 bg-warning/10",
    iconClass: "text-warning",
    label: "注意",
  },
};

export function Callout({
  variant = "note",
  title,
  children,
}: {
  variant?: CalloutVariant;
  title: string;
  children: ReactNode;
}) {
  const { icon: Icon, className, iconClass, label } = variantConfig[variant];
  return (
    <aside
      role="note"
      aria-label={`${label}: ${title}`}
      className={`my-6 flex gap-3 rounded-lg border px-4 py-3 text-sm leading-6 ${className}`}
    >
      <Icon
        aria-hidden="true"
        className={`mt-0.5 h-5 w-5 shrink-0 ${iconClass}`}
      />
      <div className="min-w-0">
        <p className="mb-1 font-semibold text-foreground">{title}</p>
        <div className="text-foreground/90">{children}</div>
      </div>
    </aside>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Button } from "@gunjo/ui";
import { IconLink, IconCheck, IconBrandX } from "@tabler/icons-react";

export function ShareButtons({ title }: { title: string }) {
  const [copied, setCopied] = useState(false);
  // Resolved after mount so server and client markup match (no hydration drift).
  const [shareUrl, setShareUrl] = useState("");

  useEffect(() => {
    setShareUrl(window.location.href);
  }, []);

  async function copyLink() {
    if (!shareUrl) return;
    try {
      await navigator.clipboard.writeText(shareUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2500);
    } catch {
      // clipboard may be unavailable (insecure context); fail silently
    }
  }

  const xHref = shareUrl
    ? `https://twitter.com/intent/tweet?text=${encodeURIComponent(
        title
      )}&url=${encodeURIComponent(shareUrl)}`
    : "https://twitter.com/intent/tweet?text=" + encodeURIComponent(title);

  return (
    <div className="flex flex-wrap gap-2">
      <Button variant="outline" size="sm" onClick={copyLink}>
        {copied ? (
          <>
            <IconCheck aria-hidden="true" className="mr-1.5 h-4 w-4" />
            リンクをコピーしました
          </>
        ) : (
          <>
            <IconLink aria-hidden="true" className="mr-1.5 h-4 w-4" />
            リンクをコピー
          </>
        )}
      </Button>
      <Button variant="outline" size="sm" asChild>
        <a href={xHref} target="_blank" rel="noopener noreferrer">
          <IconBrandX aria-hidden="true" className="mr-1.5 h-4 w-4" />
          Xでシェア
        </a>
      </Button>
    </div>
  );
}
